// CSAT official scored key for verification (disputed picks marked).
const KEY = 'B,B,B,A,B,B,D,B,C,B,D,A,D,C,B,A,A,B,B,C,C,C,B,D,C,C,C,D,B,D,A,C,D,D,D,D,D,B,C,D,C,B,A,C,A,B,B,A,A,A,D,B,C,C,D,C,D,A,B,D,A,D,C,D,A,D,A,B,D,D,D,B,D,A,B,A,A,D,B,C'.split(',')

// Internal authoring categories → KAUTILYA CSAT content parameters (the 4 taggable sections).
// The 3 cross-cutting skills (Speed, Guessing, Smartness) are derived by the scoring engine.
const SUBJECT_MAP = { Comprehension:'ReadingComprehension', QuantAptitude:'Maths', Reasoning:'Reasoning', DecisionMaking:'Misc' }
const CAT_ABBR = { Comprehension:'CMP', QuantAptitude:'QNT', Reasoning:'RSN', DecisionMaking:'DCN' }
const DIFF_BY_CAT = { Comprehension:'Medium', QuantAptitude:'Hard', Reasoning:'Medium', DecisionMaking:'Easy' }
const TIME_BY_CAT = { Comprehension:100, QuantAptitude:140, Reasoning:115, DecisionMaking:70 }
const ELIM_BY_CAT = {
  Comprehension:'Re-read only the lines the options paraphrase; reject any option that adds a claim the passage never makes.',
  QuantAptitude:'Plug the answer options back in, or estimate the magnitude, to discard impossible values fast.',
  Reasoning:'Build the grid or diagram from the fixed clues first, then test each option against it.',
  DecisionMaking:'Reject the extreme, passive, or culturally insensitive options; choose the balanced, proactive one.',
}
function slug(s){ return s.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'') }

// verify
let mism = []
for (const q of Q){ if (q.a !== KEY[q.n-1]) mism.push(`Q${q.n}: data=${q.a} key=${KEY[q.n-1]}`) }
console.log('count:', Q.length)
console.log('answer mismatches vs scored key:', mism.length ? mism.join(' | ') : 'NONE')
const inc = Q.filter(q=>q.o.length!==4 || !q.q || !q.a)
console.log('incomplete:', inc.map(q=>q.n).join(',')||'none')
const cats={}; Q.forEach(q=>cats[q.c]=(cats[q.c]||0)+1); console.log('categories:', JSON.stringify(cats))
console.log('disputed:', Q.filter(q=>q.disputed).map(q=>q.n).join(','))

const questions = Q.map(q => {
  const text = q.p ? `${P[q.p]}\n\n${q.q}` : q.q
  const diagnoses = [slug(q.c), slug(q.t), '2026', 'official-paper', 'csat']
  if (q.disputed) diagnoses.push('key-disputed')
  if (q.decmaking) diagnoses.push('decision-making-no-neg-in-real-exam')
  return {
    question_id: `P2026CSAT-${String(q.n).padStart(3,'0')}`,
    num: q.n,
    subject: SUBJECT_MAP[q.c],
    topic: q.t,
    subtopic: `UPSC 2026 Prelims CSAT (Paper II) — Q${q.n}`,
    format: q.fmt || 'single',
    difficulty: DIFF_BY_CAT[q.c],
    expected_time_sec: TIME_BY_CAT[q.c],
    text,
    options: { A: q.o[0], B: q.o[1], C: q.o[2], D: q.o[3] },
    answer: q.a,
    explanation: q.x,
    elimination_path: ELIM_BY_CAT[q.c],
    diagnoses,
  }
})

const out = {
  paper: 3,
  title: 'UPSC Civil Services Prelims 2026 — CSAT Paper II (Official)',
  source: 'official_upsc_2026_prelims_csat',
  questions,
}
fs.writeFileSync('data/question-bank/paper-03.json', JSON.stringify(out, null, 2))
console.log('wrote data/question-bank/paper-03.json with', questions.length, 'questions')
